      || statusData.brightnessOverlayVisible || window.mediaOverlayActive
      || window.appLauncherActive || window.wifiSelectorActive
      || window.bluetoothSelectorActive || window.updateSelectorActive
    readonly property real bounceDistance: 8
    readonly property real targetWidth: window.appLauncherActive
