      : window.updateSelectorActive ? updateSelector.implicitHeight : 36
    property real animatedWidth: 0
    property real animatedHeight: 0
    property real widthOvershoot: 0
    property real heightOvershoot: 0
    property bool geometryReady: false

    anchors.horizontalCenter: parent.horizontalCenter
    anchors.top: parent.top
    width: animatedWidth
    height: animatedHeight
    radius: 18
    color: "#181926"
    clip: true
    opacity: window.entered ? 1 : 0

    function bounceWidth() {
      if (!geometryReady)
        return;
      widthBounce.stop();
      if (Math.abs(targetWidth - animatedWidth) < 0.01) {
